import sympy as sp
q=sp.symbols('q')
def qint(k):
    return sum(q**i for i in range(k))
@lru_cache(None)
def Stir(n,k):
    if n==0: return sp.Integer(1) if k==0 else sp.Integer(0)
    if k<0 or k>n: return sp.Integer(0)
    return sp.expand(qint(k)*Stir(n-1,k)+Stir(n-1,k-1))
def qfact(k):
    p=1
    for i in range(1,k+1):
        p*=qint(i)
    return sp.expand(p)
def D(n,b):
